const event = $input.first().json;
const stripeEvent = event.body || {};
const eventType = stripeEvent.type || '';
const subscription = stripeEvent.data?.object || {};

// Determine event category
let membershipEvent = '';
if (eventType.includes('created')) membershipEvent = 'created';
else if (eventType.includes('updated') && subscription.status === 'active') membershipEvent = 'updated';
else if (eventType.includes('deleted')) membershipEvent = 'canceled';
else if (eventType === 'customer.subscription.updated' && subscription.cancel_at_period_end) membershipEvent = 'canceled';
else if (eventType === 'customer.subscription.updated' && !subscription.cancel_at_period_end && subscription.status === 'active') membershipEvent = 'reactivated';
else membershipEvent = 'updated';

// Map Stripe status to internal status
const statusMap = {
  'trialing': 'trialing',
  'active': 'active',
  'past_due': 'past_due',
  'canceled': 'canceled',
  'incomplete': 'incomplete',
  'incomplete_expired': 'incomplete_expired'
};

const metadata = subscription.metadata || {};
const items = subscription.items?.data || [];
const price = items[0]?.price || {};

return {
  event_type: membershipEvent,
  stripe_event_type: eventType,
  stripe_subscription_id: subscription.id,
  stripe_customer_id: subscription.customer,
  customer_email: metadata.email || '',
  status: statusMap[subscription.status] || 'active',
  current_period_start: new Date(subscription.current_period_start * 1000).toISOString(),
  current_period_end: new Date(subscription.current_period_end * 1000).toISOString(),
  trial_start: subscription.trial_start ? new Date(subscription.trial_start * 1000).toISOString() : null,
  trial_end: subscription.trial_end ? new Date(subscription.trial_end * 1000).toISOString() : null,
  cancel_at_period_end: subscription.cancel_at_period_end || false,
  canceled_at: subscription.canceled_at ? new Date(subscription.canceled_at * 1000).toISOString() : null,
  ended_at: subscription.ended_at ? new Date(subscription.ended_at * 1000).toISOString() : null,
  plan_id: metadata.plan_id || null,
  price_cents: (price.unit_amount || metadata.price_cents || 1900),
  currency: price.currency || 'usd',
  interval: price.recurring?.interval || 'month'
};

// If no profile found, create one
if ($json.length === 0) {
  // Profile creation happens via first node output
  return {
    needs_creation: true,
    ...$json
  };
}

// Profile found - merge data
return {
  needs_creation: false,
  profile_id: $json[0].id,
  ...$json
};
